#if UNITY_EDITOR
using UnityEditor;

/// <summary>
/// Editor customizado do MusicZone: mostra a lista "conditions" (Etapa 8) com
/// o mesmo botão "+ Adicionar Condição" usado pelo NpcController, permitindo
/// escolher qualquer subclasse de NpcCondition (incluindo as de variáveis e
/// de estado de NPC) sem precisar de tocar neste editor.
/// </summary>
[CustomEditor(typeof(MusicZone))]
public class MusicZoneEditor : Editor
{
    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "conditions");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, serializedObject.FindProperty("conditions"), "Condições (Etapa 8)", typeof(NpcCondition), "Adicionar Condição");

        serializedObject.ApplyModifiedProperties();
    }
}
#endif
